// Recibe ?path=/20 AJ/Nombre Carpeta
// Devuelve {subfolder: {pdf: N, dwg: M, ...}, ...}

const rootPath = $input.first().json.query?.path || '/20 AJ';
const BASE = 'https://n8npozos.magoreal.com/webhook/nc-tekon';

async function fetchItems(path) {
  try {
    const resp = await fetch(`${BASE}?path=${encodeURIComponent(path)}`);
    if (!resp.ok) return [];
    const data = await resp.json();
    return Array.isArray(data) ? data : [];
  } catch (e) {
    return [];
  }
}

function parseName(encodedPath) {
  return decodeURIComponent(encodedPath).replace(/\/$/, '').split('/').pop();
}

function countFiles(items) {
  const counts = {};
  for (const item of items) {
    if (item.type !== 'file') continue;
    const name = decodeURIComponent(item.path).split('/').pop();
    if (!name.includes('.')) continue;
    const ext = name.split('.').pop().toLowerCase();
    counts[ext] = (counts[ext] || 0) + 1;
  }
  // Ordenar por conteo desc, luego alfabético
  return Object.fromEntries(
    Object.entries(counts).sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))
  );
}

// 1. Listar subcarpetas del path raíz
const subItems = await fetchItems(rootPath);
const subFolders = subItems.filter(i => i.type === 'folder');

// 2. Para cada subcarpeta, listar sus archivos en paralelo
const results = await Promise.all(
  subFolders.map(async (folder) => {
    const name = parseName(folder.path);
    const subPath = `${rootPath}/${name}`;
    const fileItems = await fetchItems(subPath);
    return [name, countFiles(fileItems)];
  })
);

const output = Object.fromEntries(results);
return [{ json: output }];
